INSERT INTO hcpcs_codes (code, description_official, unit_type, is_active)
VALUES ('G0137', 'Intensive outpatient services; weekly bundle, minimum of 9 services over a 7 contiguous day period, which can include individual and group therapy with physicians or psychologists (or other mental health professionals to the extent authorized under state law); occupational therapy requiring the skills of a qualified occupational therapist; services of social workers, trained psychiatric nurses, and other staff trained to work with psychiatric patients; individualized activity therapies that are not primarily recreational or diversionary; family counseling (the primary purpose of which is treatment of the individual''s condition); patient training and education (to the extent that training and educational activities are closely and clearly related to individual''s care and treatment); diagnostic services; and such other items and services (excluding meals and transportation) that are reasonable and necessary for the diagnosis or active treatment of the individual''s condition, reasonably expected to improve or maintain the individual''s condition and functional level and to prevent relapse or hospitalization, and furnished pursuant to such guidelines relating to frequency and duration of services in accordance with a physician certification and plan of treatment (provision of the services by a medicare-enrolled opioid treatment program); list separately in addition to code for primary procedure', 'quantity', true)
ON CONFLICT (code) DO UPDATE SET description_official = EXCLUDED.description_official, unit_type = EXCLUDED.unit_type;

