INSERT INTO hcpcs_codes (code, description_official, unit_type, is_active)
VALUES ('G0556', 'Advanced primary care management services for a patient with one chronic condition [expected to last at least 12 months, or until the death of the patient, which place the patient at significant risk of death, acute exacerbation/decompensation, or functional decline], or fewer, provided by clinical staff and directed by a physician or other qualified health care professional who is responsible for all primary care and serves as the continuing focal point for all needed health care services, per calendar month, with the following elements, as appropriate:    consent; ++  inform the patient of the availability of the service; that only one practitioner can furnish and be paid for the service during a calendar month; of the right to stop the services at any time (effective at the end of the calendar month); and that cost sharing may apply. ++  document in patient''s medical record that consent was obtained.    initiation during a qualifying visit for new patients or patients not seen within 3 years;    provide 24/7 access for urgent needs to care team/practitioner, including providing patients/caregivers with a way to contact health care professionals in the practice to discuss urgent needs regardless of the time of day or day of week;    continuity of care with a designated member of the care team with whom the patient is able to schedule successive routine appointments;     deliver care in alternative ways to traditional office visits to best meet the patient''s needs, such as home visits and/or expanded hours;    overall comprehensive care management; ++  systematic needs assessment (medical and psychosocial). ++  system-based approaches to ensure receipt of preventive services. ++  medication reconciliation, management and oversight of self-management.    development, implementation, revision, and maintenance of an electronic patient-centered comprehensive care plan with typical care plan elements when clinically relevant; ++  care plan is available timely within and outside the billing practice as appropriate to individuals involved in the beneficiary''s care, can be routinely accessed and updated by care team/practitioner, and copy of care plan to patient/caregiver; coordination of care transitions between and among health care providers and settings, including referrals to other clinicians and follow-up after an emergency department visit and discharges from hospitals, skilled nursing facilities or other health care facilities as applicable; ++  ensure timely exchange of electronic health information with other practitioners and providers to support continuity of care. ++  ensure timely follow-up communication (direct contact, telephone, electronic) with the patient and/or caregiver after an emergency department visit and discharges from hospitals, skilled nursing facilities, or other health care facilities, within 7 calendar days of discharge, as clinically indicated.    ongoing communication and coordinating receipt of needed services from practitioners, home- and community-based service providers, community-based social service providers, hospitals, and skilled nursing facilities (or other health care facilities), and document communication regarding the patient''s psychosocial strengths and needs, functional deficits, goals, preferences, and desired outcomes, including cultural and linguistic factors, in the patient''s medical record;    enhanced opportunities for the beneficiary and any caregiver to communicate with the care team/practitioner regarding the beneficiary''s care through the use of asynchronous non-face-to-face consultation methods other than telephone, such as secure messaging, email, internet, or patient portal, and other communication-technology based services, including remote evaluation of pre-recorded patient information and interprofessional telephone/internet/ehr referral service(s), to maintain ongoing communication with patients, as appropriate; ++  ensure access to patient-initiated digital communications that require a clinical decision, such as virtual check-ins and digital online assessment and management and e/m visits (or e-visits).      analyze patient population data to identify gaps in care and offer additional interventions, as appropriate;    risk stratify the practice population based on defined diagnoses, claims, or other electronic data to identify and target services to patients;     be assessed through performance measurement of primary care quality, total cost of care, and meaningful use of certified ehr technology', 'quantity', true)
ON CONFLICT (code) DO UPDATE SET description_official = EXCLUDED.description_official, unit_type = EXCLUDED.unit_type;

INSERT INTO hcpcs_codes (code, description_official, unit_type, is_active)
VALUES ('G0557', 'Advanced primary care management services for a patient with multiple (two or more) chronic conditions expected to last at least 12 months, or until the death of the patient, which place the patient at significant risk of death, acute exacerbation/decompensation, or functional decline, provided by clinical staff and directed by a physician or other qualified health care professional who is responsible for all primary care and serves as the continuing focal point for all needed health care services, per calendar month, with the following elements, as appropriate:    consent; ++  inform the patient of the availability of the service; that only one practitioner can furnish and be paid for the service during a calendar month; of the right to stop the services at any time (effective at the end of the calendar month); and that cost sharing may apply. ++  document in patient''s medical record that consent was obtained. initiation during a qualifying visit for new patients or patients not seen within 3 years;    provide 24/7 access for urgent needs to care team/practitioner, including providing patients/caregivers with a way to contact health care professionals in the practice to discuss urgent needs regardless of the time of day or day of week;    continuity of care with a designated member of the care team with whom the patient is able to schedule successive routine appointments;     deliver care in alternative ways to traditional office visits to best meet the patient''s needs, such as home visits and/or expanded hours;    overall comprehensive care management; ++  systematic needs assessment (medical and psychosocial). ++  system-based approaches to ensure receipt of preventive services. ++  medication reconciliation, management and oversight of self-management.    development, implementation, revision, and maintenance of an electronic patient-centered comprehensive care plan;  ++  care plan is available timely within and outside the billing practice as appropriate to individuals involved in the beneficiary''s care, can be routinely accessed and updated by care team/practitioner, and copy of care plan to patient/caregiver;    coordination of care transitions between and among health care providers and settings, including referrals to other clinicians and follow-up after an emergency department visit and discharges from hospitals, skilled nursing facilities or other health care facilities as applicable; ++  ensure timely exchange of electronic health information with other practitioners and providers to support continuity of care. ++  ensure timely follow-up communication (direct contact, telephone, electronic) with the patient and/or caregiver after an emergency department visit and discharges from hospitals, skilled nursing facilities, or other health care facilities, within 7 calendar days of discharge, as clinically indicated.    ongoing communication and coordinating receipt of needed services from practitioners, home- and community-based service providers, community-based social service providers, hospitals, and skilled nursing facilities (or other health care facilities), and document communication regarding the patient''s psychosocial strengths and needs, functional deficits, goals, preferences, and desired outcomes, including cultural and linguistic factors, in the patient''s medical record;    enhanced opportunities for the beneficiary and any caregiver to communicate with the care team/practitioner regarding the beneficiary''s care through the use of asynchronous non-face-to-face consultation methods other than telephone, such as secure messaging, email, internet, or patient portal, and other communication-technology based services, including remote evaluation of pre-recorded patient information and interprofessional telephone/internet/ehr referral service(s), to maintain ongoing communication with patients, as appropriate; ++  ensure access to patient-initiated digital communications that require a clinical decision, such as virtual check-ins and digital online assessment and management and e/m visits (or e-visits). analyze patient population data to identify gaps in care and offer additional interventions, as appropriate;    risk stratify the practice population based on defined diagnoses, claims, or other electronic data to identify and target services to patients;    be assessed through performance measurement of primary care quality, total cost of care, and meaningful use of certified ehr technology', 'quantity', true)
ON CONFLICT (code) DO UPDATE SET description_official = EXCLUDED.description_official, unit_type = EXCLUDED.unit_type;

