INSERT INTO hcpcs_codes (code, description_official, unit_type, is_active)
VALUES ('G9978', 'Remote in-home visit for the evaluation and management of a new patient for use only in a medicare-approved bundled payments for care improvement advanced (bpci advanced) model episode of care, which requires these 3 key components: a problem focused history; a problem focused examination; and straightforward medical decision making, furnished in real time using interactive audio and video technology.  counseling and coordination of care with other physicians, other qualified health care professionals or agencies are provided consistent with the nature of the problem(s) and the needs of the patient or the family or both. usually, the presenting problem(s) are self limited or minor. typically, 10 minutes are spent with the patient or family or both via real time, audio and video intercommunications technology', 'quantity', true)
